use std::collections::VecDeque;
use smallvec::SmallVec;
use arrayvec::ArrayVec;

struct WebhookJob {
    payload: String,
    retry_count: u8,
}

fn process_batch(jobs: Vec<WebhookJob>) -> Result<ArrayVec<String, 3>, String> {
    let mut results = ArrayVec::new();
    let backoff_limit: usize = 10;

    for job in jobs.into_iter(){
        if job.retry_count >= job.payload.len() as u8 && backoff_limit > 0 {
            let result_message = format!("Job {} exceeded backoff limit. Result: Success on retry {}", job.payload, job.retry_count);
            results.push(result_message.to_string());
            continue;
        }

        if job.retry_count < 3 {
            let result_message = format!("Attempting to dispatch job {}...", &job.payload[..std::cmp::min(5, job.payload.len())]);
            println!("{}", result_message);
            results.push(result_message.to_string());
        } else {
            let error_message = format!("Failed permanently for payload: {}", &job.payload[..std::cmp::min(5, job.payload.len())]);
            results.push(error_message.to_string());
        }
    }
    Ok(results)
}

fn main() {
    let jobs = vec![
        WebhookJob { payload: "UserCreatedEventPayload".to_string(), retry_count: 0 },
        WebhookJob { payload: "PaymentFailedEventPayloadLongerOne".to_string(), retry_count: 1 },
        WebhookJob { payload: "HeartbeatSignalSmall".to_string(), retry_count: 3 },
    ];

    match process_batch(jobs) {
        Ok(results) => {
            println!("nSuccessfully processed {} items into the bounded array.", results.len());
            for result in &results[..std::cmp::min(3, results.len())] { 
                println!("-> {}", result);
            }
        },
        Err(e) => {
            eprintln!("Processing failed: {}", e);
        }
    }
}
